1	// SyncPlay - 房间状态机 (v0.6 FR-3)
2	// 6 态: no_room / connecting / in_room_no_video / in_room_waiting_peer_video /
3	//       in_room_synced / in_room_mismatch
4	//
5	// 设计目标: 房间生命周期(创建/进入/退出) 跟视频加载解耦.
6	// 同步指令(sync engine) 只在 in_room_synced 时启动, 其他状态都关闭.
7	//
8	// 浏览器通过 window.SyncPlayRoomState 使用, Node 测试通过 require 使用.
9	
10	(function (root, factory) {
11	  if (typeof module === 'object' && module.exports) {
12	    module.exports = factory();
13	  } else {
14	    root.SyncPlayRoomState = factory();
15	  }
16	}(typeof self !== 'undefined' ? self : this, function () {
17	  'use strict';
18	
19	  // ============ 状态常量 ============
20	  const STATES = Object.freeze({
21	    NO_ROOM: 'no_room',
22	    CONNECTING: 'connecting',
23	    IN_ROOM_NO_VIDEO: 'in_room_no_video',
24	    IN_ROOM_WAITING_PEER_VIDEO: 'in_room_waiting_peer_video',
25	    IN_ROOM_SYNCED: 'in_room_synced',
26	    IN_ROOM_MISMATCH: 'in_room_mismatch',
27	  });
28	
29	  // ============ 合法转移图 ============
30	  // 说明:
31	  //   - 任意 in_room_* 状态都能 → connecting (peer lost, 等待重连)
32	  //   - 任意状态都能 → no_room (用户点"退出房间")
33	  //   - video 子状态间转移: loaded/peer_loaded/match 三维
34	  const TRANSITIONS = Object.freeze({
35	    no_room:                       ['connecting'],
36	    connecting:                    ['in_room_no_video', 'no_room'],
37	    in_room_no_video:              ['in_room_waiting_peer_video', 'in_room_synced', 'in_room_mismatch', 'connecting', 'no_room'],
38	    in_room_waiting_peer_video:    ['in_room_synced', 'in_room_mismatch', 'in_room_no_video', 'connecting', 'no_room'],
39	    in_room_synced:                ['in_room_mismatch', 'in_room_waiting_peer_video', 'in_room_no_video', 'connecting', 'no_room'],
40	    in_room_mismatch:              ['in_room_synced', 'in_room_waiting_peer_video', 'in_room_no_video', 'connecting', 'no_room'],
41	  });
42	
43	  // ============ RoomStateMachine ============
44	
45	  class RoomStateMachine {
46	    constructor() {
47	      this._state = STATES.NO_ROOM;
48	      this._listeners = [];
49	    }
50	
51	    /** 当前状态 */
52	    get state() {
53	      return this._state;
54	    }
55	
56	    /** 判断是否处于某状态 (单参数形式) */
57	    is(state) {
58	      return this._state === state;
59	    }
60	
61	    /**
62	     * 状态转移
63	     * @param {string} next 目标状态 (STATES.*)
64	     * @returns {boolean} 是否真的发生了转移 (true = 成功, false = 非法或相同状态)
65	     */
66	    setState(next) {
67	      if (this._state === next) return false;
68	      const allowed = TRANSITIONS[this._state] || [];
69	      if (!allowed.includes(next)) {
70	        // 静默忽略非法转移; 调用方可以监听 state 自行检查
71	        if (typeof console !== 'undefined') {
72	          console.warn(`[room-state] illegal transition: ${this._state} -> ${next}`);
73	        }
74	        return false;
75	      }
76	      const prev = this._state;
77	      this._state = next;
78	      for (const fn of this._listeners) {
79	        try { fn(next, prev); } catch (e) {
80	          if (typeof console !== 'undefined') console.error('[room-state] listener error', e);
81	        }
82	      }
83	      return true;
84	    }
85	
86	    /**
87	     * 强制设状态 (不走 TRANSITIONS 校验, 用于测试 / 错误恢复)
88	     * 不触发任何 listener.
89	     */
90	    _forceState(next) {
91	      this._state = next;
92	    }
93	
94	    /**
95	     * 订阅状态变化
96	     * @param {(newState: string, oldState: string) => void} fn
97	     * @returns {() => void} 取消订阅的函数
98	     */
99	    onStateChange(fn) {
100	      this._listeners.push(fn);
101	      return () => {
102	        this._listeners = this._listeners.filter(f => f !== fn);
103	      };
104	    }
105	
106	    /** 同步引擎是否应该运行 (只有 synced 才发送 play/pause/seek/heartbeat/drift) */
107	    canSync() {
108	      return this._state === STATES.IN_ROOM_SYNCED;
109	    }
110	  }
111	
112	  return { STATES, TRANSITIONS, RoomStateMachine };
113	}));
114

