28	   */
29	  class SyncEngine {
30	    /**
31	     * @param {HTMLVideoElement|Object} video
32	     * @param {Function} send - 发送消息的函数
33	     * @param {Object} [config] - 可选配置，覆盖 DEFAULT_CONFIG
34	     */
35	    constructor(video, send, config) {
36	      this.video = video;
37	      this.send = send;
38	      this.guardUntil = 0;          // 接收方：在 guardUntil 之前忽略本地事件
39	      this.heartbeatTs = 0;         // 上次心跳的本地时间戳
40	      this.lastRtt = -1;            // 最近一次往返延迟
41	      this.driftOffset = 0;         // 漂移偏移（我与对方的 currentTime 之差）
42	      this.driftTimer = null;
43	      this.heartbeatTimer = null;
44	      this._config = Object.assign({}, DEFAULT_CONFIG, config || {});
45	      this.bindVideoEvents();
46	    }
47	
48	    get CONFIG() {
49	      return this._config;
50	    }
51	
52	    bindVideoEvents() {
53	      // 收到远程同步指令时设置一个"屏蔽窗口"，期间本地事件不上报
