1	// SyncPlay - 视频匹配检测 (v0.6 FR-3)
2	// 比较两端视频信息是否"同一视频" — 用于触发 in_room_synced / in_room_mismatch 状态.
3	//
4	// 匹配策略 (per REQUIREMENTS.md FR-3): URL + 文件名 + 时长 三重校验, 任一通过即匹配.
5	//   - URL 相同: https://example.com/foo.mp4 === https://example.com/foo.mp4
6	//   - 文件名相同: myvideo.mp4 === myvideo.mp4 (用于本地 blob: URL, blob URL 每次会话唯一)
7	//   - 时长差 < 1s: 浮点误差容忍
8	//
9	// 浏览器通过 window.SyncPlayVideoMatch 使用, Node 测试通过 require 使用.
10	
11	(function (root, factory) {
12	  if (typeof module === 'object' && module.exports) {
13	    module.exports = factory();
14	  } else {
15	    root.SyncPlayVideoMatch = factory();
16	  }
17	}(typeof self !== 'undefined' ? self : this, function () {
18	  'use strict';
19	
20	  /**
21	   * 比较两端视频信息是否匹配
22	   * @param {VideoInfo|null|undefined} a
23	   * @param {VideoInfo|null|undefined} b
24	   * @returns {boolean}
25	   */
26	  function videosMatch(a, b) {
27	    if (!a || !b) return false;
28	    if (a.loaded === false || b.loaded === false) return false;
29	
30	    // 优先级 1: URL (去掉 query/fragment 后比较更稳)
31	    if (a.url && b.url) {
32	      return normalizeUrl(a.url) === normalizeUrl(b.url);
33	    }
34	
35	    // 优先级 2: 文件名 (处理本地文件: blob: URL 每次不同, 比不了 URL)
36	    if (a.fileName && b.fileName) {
37	      return a.fileName === b.fileName;
38	    }
39	
40	    // 优先级 3: 时长 (浮点容差 1s)
41	    if (a.duration && b.duration) {
42	      return Math.abs(a.duration - b.duration) < 1;
43	    }
44	
45	    return false;
46	  }
47	
48	  /**
49	   * 规范化 URL: 去掉 fragment, query 保留 (URL 中常有 token)
50	   * 注意: 短链 / 重定向场景下两端 URL 可能不同, 这种靠 fileName / duration 兜底
51	   */
52	  function normalizeUrl(u) {
53	    if (!u) return '';
54	    try {
55	      // 简单处理: 去 fragment (e.g. #t=10)
56	      const hashIdx = u.indexOf('#');
57	      return hashIdx === -1 ? u : u.substring(0, hashIdx);
58	    } catch (e) {
59	      return u;
60	    }
61	  }
62	
63	  /**
64	   * 从 <video> 元素 + 加载 label 提取 VideoInfo
65	   * @param {HTMLVideoElement|Object} video
66	   * @param {string} [label] - 显示用 label (e.g. "本地: myvideo.mp4" 或 "加载中: foo.mp4")
67	   * @returns {VideoInfo|null}
68	   */
69	  function describeVideo(video, label) {
70	    if (!video || !video.src) return null;
71	    const info = { loaded: true };
72	    // URL load: src 是 http(s):// 或 data:
73	    if (/^(https?|data):/i.test(video.src)) {
74	      info.url = video.src;
75	    }
76	    // 本地 file load: src 是 blob: — 用 label 兜底出 fileName
77	    if (label) {
78	      const m = label.match(/(?:本地[:\s]|加载中[:\s]|已加载[:\s])(.+)$/);
79	      if (m) info.fileName = m[1].trim();
80	    }
81	    if (isFinite(video.duration) && video.duration > 0) {
82	      info.duration = video.duration;
83	    }
84	    return Object.keys(info).length > 1 ? info : null;
85	  }
86	
87	  /**
88	   * 构造"无视频" info (用于清空)
89	   */
90	  function emptyVideoInfo() {
91	    return { loaded: false };
92	  }
93	
94	  return { videosMatch, describeVideo, normalizeUrl, emptyVideoInfo };
95	}));
