1	#!/usr/bin/env node
2	/**
3	 * SyncPlay 集成测试
4	 *
5	 * 测试场景：
6	 * 1. 启动 HTTP 静态文件服务器（client/ -> :8080）
7	 * 2. 启动 Playwright 浏览器实例（user A / user B）
8	 * 3. 加载视频 -> 创建房间 -> 加入房间
9	 * 4. 尝试建立 PeerJS WebRTC 连接
10	 * 5. 如果连接成功，测试播放/暂停/跳转同步
11	 *
12	 * 注意：WebRTC 在同一机器的两个 Playwright 实例之间可能因 NAT/防火墙
13	 * 或 Chrome 安全策略而无法建立连接。这是环境限制，不是代码 bug。
14	 */
15	
16	const { chromium } = require('playwright');
17	const { spawn, execSync } = require('child_process');
18	const path = require('path');
19	const fs = require('fs');
20	
21	const PROJECT_ROOT = path.resolve(__dirname, '..');
22	const CLIENT_DIR = path.join(PROJECT_ROOT, 'client');
23	const SERVER_DIR = path.join(PROJECT_ROOT, 'server');
24	// WEB_ROOT: HTTP 服务根目录设到 src/ 顶层,这样 ../shared/ 能服务
25	const WEB_ROOT = path.join(PROJECT_ROOT, 'src');
26	const TEST_VIDEO = path.join(CLIENT_DIR, 'test-video.mp4');
27	
28	const HTTP_PORT = 8080;
29	
30	let httpServer = null;
31	let browser = null;
32	
33	const results = {
34	  passed: [],
35	  failed: [],
36	};
37	
38	function log(msg, level = 'INFO') {
39	  const ts = new Date().toISOString().split('T')[1].slice(0, 8);
40	  console.log(`[${ts}] [${level}] ${msg}`);
41	}
42	
43	function pass(name) {
44	  results.passed.push(name);
45	  console.log(`  ✅ PASS: ${name}`);
46	}
47	
48	function fail(name, reason) {
49	  results.failed.push({ name, reason });
50	  console.log(`  ❌ FAIL: ${name} — ${reason}`);
51	}
52	
53	/** 启动 HTTP 静态文件服务器(根目录为 src/ 顶层) */
54	function startHttpServer() {
55	  return new Promise((resolve, reject) => {
